  ('diplomatic-20fe77d5-moex-00459', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-111-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '下列有關聯合國安全理事會（UNSC）的敘述，何者錯誤？', '["聯合國安全理事會由15個國家組成，包括5個常任理事國及任期三年的10個非常任理事國", "聯合國安全理事會可調查可能引起國際摩擦的任何爭端或局勢", "日本於今年6月獲選為非常任理事國，將自2023年1月起加入聯合國安全理事會", "每個理事國的代表必須常駐聯合國總部，使聯合國安全理事會可於必要時隨時召開會議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:36+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00460', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-111-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '「全球化」包括諸多面向，下列有關「全球化」的論述，何者錯誤？', '["超全球主義者傾向於相信，歐洲聯盟最終將取代個別成員國", "當前世界主要經濟體的整合程度並未較第一次世界大戰前更高", "懷疑論者傾向於相信，民族國家即將衰退", "今日南北國家之間的發展與財富差距持續擴大而非縮小"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:36+00:00", "source_pdf_sha1": "e563283a7bfd", "answer_pdf_sha1": "9d2419faf7f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
